import type { Chain } from 'viem'
import { arbitrum, base, mainnet } from 'viem/chains'

export type SupportedChainId = 1 | 8453 | 42161

export const SUPPORTED_CHAINS = {
  [mainnet.id]: mainnet,
  [base.id]: base,
  [arbitrum.id]: arbitrum,
} as const satisfies Record<SupportedChainId, Chain>

export const SUPPORTED_CHAIN_IDS = Object.keys(SUPPORTED_CHAINS).map(Number) as SupportedChainId[]

export function isSupportedChain(chainId: number): chainId is SupportedChainId {
  return chainId in SUPPORTED_CHAINS
}

export function getChain(chainId: SupportedChainId): Chain {
  return SUPPORTED_CHAINS[chainId]
}

export type NetworkName = 'ethereum' | 'base' | 'arbitrum'

export const CHAIN_ID_TO_NETWORK: Record<SupportedChainId, NetworkName> = {
  1: 'ethereum',
  8453: 'base',
  42161: 'arbitrum',
}

export const NETWORK_TO_CHAIN_ID: Record<NetworkName, SupportedChainId> = {
  ethereum: 1,
  base: 8453,
  arbitrum: 42161,
}
