import type { Address, PublicClient } from 'viem'
import { MERKL_DISTRIBUTOR_ADDRESSES } from '../constants/merkl'
import { merklDistributorAbi } from '../constants/merkl-abi'

export async function getClaimedAmount(
  publicClient: PublicClient,
  userAddress: Address,
  tokenAddress: Address,
  chainId: number,
): Promise<bigint> {
  const distributorAddress = MERKL_DISTRIBUTOR_ADDRESSES[chainId]

  if (!distributorAddress) {
    throw new Error(`No Merkl distributor found for chain ${chainId}`)
  }

  return publicClient.readContract({
    address: distributorAddress,
    abi: merklDistributorAbi,
    functionName: 'claimed',
    args: [userAddress, tokenAddress],
  })
}

export async function getClaimedAmounts(
  publicClient: PublicClient,
  userAddress: Address,
  tokenAddresses: Address[],
  chainId: number,
): Promise<Map<Address, bigint>> {
  const distributorAddress = MERKL_DISTRIBUTOR_ADDRESSES[chainId]

  if (!distributorAddress) {
    throw new Error(`No Merkl distributor found for chain ${chainId}`)
  }

  const results = await Promise.all(
    tokenAddresses.map((token) =>
      publicClient.readContract({
        address: distributorAddress,
        abi: merklDistributorAbi,
        functionName: 'claimed',
        args: [userAddress, token],
      }),
    ),
  )

  const claimedMap = new Map<Address, bigint>()
  tokenAddresses.forEach((token, index) => {
    claimedMap.set(token, results[index] ?? 0n)
  })

  return claimedMap
}
