import type { Address, PublicClient } from 'viem'
import { encodeFunctionData } from 'viem'
import { erc20Abi, yoGatewayAbi } from '../constants/abis'
import { YO_GATEWAY_ADDRESS } from '../constants/addresses'
import type { PreparedTransaction } from '../types'
import { applySlippage } from '../utils/math'
import { isNativeToken } from '../utils/native'
import { validateAddress, validateAmount } from '../utils/validation'
import type { DepositViaGatewayParams } from './deposit'
import type { RedeemViaGatewayParams } from './redeem'

export interface PrepareApproveParams {
  token: Address
  spender?: Address
  amount: bigint
}

export function prepareApprove(params: PrepareApproveParams): PreparedTransaction {
  const { token, spender = YO_GATEWAY_ADDRESS, amount } = params

  const data = encodeFunctionData({
    abi: erc20Abi,
    functionName: 'approve',
    args: [spender, amount],
  })

  return { to: token, data, value: 0n }
}

export async function prepareDeposit(
  publicClient: PublicClient,
  params: DepositViaGatewayParams,
): Promise<PreparedTransaction> {
  const { vault, amount, recipient, slippageBps = 50, partnerId = 9999 } = params

  validateAddress(vault, 'vault')
  validateAmount(amount, 'amount')

  if (!recipient) {
    throw new Error('[yo-kit] recipient is required for prepareDeposit')
  }

  const expectedShares = await publicClient.readContract({
    address: YO_GATEWAY_ADDRESS,
    abi: yoGatewayAbi,
    functionName: 'quotePreviewDeposit',
    args: [vault, amount],
  })

  const minShares = applySlippage(expectedShares, slippageBps)

  const data = encodeFunctionData({
    abi: yoGatewayAbi,
    functionName: 'deposit',
    args: [vault, amount, minShares, recipient, partnerId],
  })

  return { to: YO_GATEWAY_ADDRESS, data, value: 0n }
}

export async function prepareRedeem(
  publicClient: PublicClient,
  params: RedeemViaGatewayParams,
): Promise<PreparedTransaction> {
  const { vault, shares, recipient, slippageBps = 50, partnerId = 9999 } = params

  validateAddress(vault, 'vault')
  validateAmount(shares, 'shares')

  if (!recipient) {
    throw new Error('[yo-kit] recipient is required for prepareRedeem')
  }

  const expectedAssets = await publicClient.readContract({
    address: YO_GATEWAY_ADDRESS,
    abi: yoGatewayAbi,
    functionName: 'quotePreviewRedeem',
    args: [vault, shares],
  })

  const minAssetsOut = params.minAssetsOut ?? applySlippage(expectedAssets, slippageBps)

  const data = encodeFunctionData({
    abi: yoGatewayAbi,
    functionName: 'redeem',
    args: [vault, shares, minAssetsOut, recipient, partnerId],
  })

  return { to: YO_GATEWAY_ADDRESS, data, value: 0n }
}

export interface PrepareDepositWithApprovalParams extends DepositViaGatewayParams {
  token: Address
  owner: Address
}

export async function prepareDepositWithApproval(
  publicClient: PublicClient,
  params: PrepareDepositWithApprovalParams,
): Promise<PreparedTransaction[]> {
  const { token, owner, amount } = params

  const txs: PreparedTransaction[] = []

  if (!isNativeToken(token)) {
    const allowance = await publicClient.readContract({
      address: token,
      abi: erc20Abi,
      functionName: 'allowance',
      args: [owner, YO_GATEWAY_ADDRESS],
    })

    if (allowance < amount) {
      txs.push(prepareApprove({ token, amount }))
    }
  }

  const depositTx = await prepareDeposit(publicClient, params)
  txs.push(depositTx)

  return txs
}

export interface PrepareRedeemWithApprovalParams extends RedeemViaGatewayParams {
  owner: Address
}

export async function prepareRedeemWithApproval(
  publicClient: PublicClient,
  params: PrepareRedeemWithApprovalParams,
): Promise<PreparedTransaction[]> {
  const { vault, owner, shares } = params

  const txs: PreparedTransaction[] = []

  // Check if vault shares need approval for the gateway
  const allowance = await publicClient.readContract({
    address: vault,
    abi: erc20Abi,
    functionName: 'allowance',
    args: [owner, YO_GATEWAY_ADDRESS],
  })

  if (allowance < shares) {
    txs.push(prepareApprove({ token: vault, amount: shares }))
  }

  const redeemTx = await prepareRedeem(publicClient, params)
  txs.push(redeemTx)

  return txs
}
