import type { Address } from 'viem'
import type { ApiClient } from '../api/client'
import { getAllTimeRewards, getUserRewardsByAsset, getWeeklyRewards } from '../api/leaderboard'
import { getPrices } from '../api/pricing'
import type {
  AllTimeRewardsResponse,
  DailyAllocationSnapshot,
  FormattedValue,
  GlobalVaultHistoryResponse,
  Network,
  PendingRedeem,
  PerformanceBenchmark,
  PriceMap,
  SharePriceHistoryPoint,
  TimeseriesPoint,
  TotalTvlTimeseriesPoint,
  UserBalances,
  UserHistoryItem,
  UserPerformance,
  UserRewardsByAssetResponse,
  UserSnapshot,
  VaultActivityFilters,
  VaultHistoryResponse,
  VaultPercentile,
  VaultPerformance,
  VaultSnapshot,
  VaultStatsItem,
  WeeklyRewardsResponse,
} from '../api/types'
import {
  getUserBalances,
  getUserPendingRedemptions,
  getUserPerformance,
  getUserSnapshots,
  getUserTransactionHistory,
} from '../api/user'
import {
  getGlobalVaultHistory,
  getPerformanceBenchmark,
  getSharePriceHistory,
  getTotalTvlTimeseries,
  getVaultAllocationsTimeSeries,
  getVaultHistory,
  getVaultHistoryAllNetworks,
  getVaultPendingRedeems,
  getVaultPercentile,
  getVaultPerformance,
  getVaults,
  getVaultSnapshot,
  getVaultTvlTimeseries,
  getVaultYieldTimeseries,
} from '../api/vault'
import { getVaultByAddress } from '../constants/addresses'
import { CHAIN_ID_TO_NETWORK, type SupportedChainId } from '../constants/chains'

export class VaultApiService {
  private readonly network: Network

  constructor(
    private readonly apiClient: ApiClient,
    chainId: SupportedChainId,
  ) {
    this.network = CHAIN_ID_TO_NETWORK[chainId]
  }

  // Vault

  getVaults(options?: { secondary?: boolean }): Promise<VaultStatsItem[]> {
    return getVaults(this.apiClient, options)
  }

  getVaultSnapshot(vaultAddress: Address): Promise<VaultSnapshot> {
    return getVaultSnapshot(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getVaultHistory(vaultAddress: Address, limit?: number): Promise<VaultHistoryResponse> {
    return getVaultHistory(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress, limit)
  }

  getVaultHistoryAllNetworks(
    vaultAddress: Address,
    options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
  ): Promise<GlobalVaultHistoryResponse> {
    return getVaultHistoryAllNetworks(this.apiClient, vaultAddress, options)
  }

  getGlobalVaultHistory(
    options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
  ): Promise<GlobalVaultHistoryResponse> {
    return getGlobalVaultHistory(this.apiClient, options)
  }

  getVaultYieldHistory(vaultAddress: Address): Promise<TimeseriesPoint[]> {
    return getVaultYieldTimeseries(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getVaultTvlHistory(vaultAddress: Address): Promise<TimeseriesPoint[]> {
    return getVaultTvlTimeseries(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getTotalTvlTimeseries(): Promise<TotalTvlTimeseriesPoint[]> {
    return getTotalTvlTimeseries(this.apiClient)
  }

  getVaultPercentile(vaultAddress: Address): Promise<VaultPercentile> {
    return getVaultPercentile(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getSharePriceHistory(vaultAddress: Address): Promise<SharePriceHistoryPoint[]> {
    return getSharePriceHistory(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getVaultAllocationsTimeSeries(vaultAddress: Address): Promise<DailyAllocationSnapshot[]> {
    return getVaultAllocationsTimeSeries(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getVaultPendingRedeems(vaultAddress: Address): Promise<FormattedValue> {
    return getVaultPendingRedeems(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getVaultPerformance(vaultAddress: Address): Promise<VaultPerformance> {
    return getVaultPerformance(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress)
  }

  getPerformanceBenchmark(vaultAddress: Address): Promise<PerformanceBenchmark> {
    return getPerformanceBenchmark(this.apiClient, vaultAddress)
  }

  // User

  getUserHistory(vaultAddress: Address, user: Address, limit?: number): Promise<UserHistoryItem[]> {
    return getUserTransactionHistory(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress, user, limit)
  }

  getUserPerformance(vaultAddress: Address, user: Address): Promise<UserPerformance> {
    return getUserPerformance(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress, user)
  }

  getPendingRedemptions(vaultAddress: Address, user: Address): Promise<PendingRedeem> {
    return getUserPendingRedemptions(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress, user)
  }

  getUserSnapshots(vaultAddress: Address, user: Address): Promise<UserSnapshot[]> {
    return getUserSnapshots(this.apiClient, this.resolveVaultNetwork(vaultAddress), vaultAddress, user)
  }

  getUserBalances(user: Address): Promise<UserBalances> {
    return getUserBalances(this.apiClient, user)
  }

  // Rewards leaderboard

  getWeeklyRewards(tokenAddress: string): Promise<WeeklyRewardsResponse> {
    return getWeeklyRewards(this.apiClient, tokenAddress)
  }

  getAllTimeRewards(tokenAddress: string): Promise<AllTimeRewardsResponse> {
    return getAllTimeRewards(this.apiClient, tokenAddress)
  }

  getUserRewardsByAsset(userAddress: Address, tokenAddress?: string): Promise<UserRewardsByAssetResponse> {
    return getUserRewardsByAsset(this.apiClient, userAddress, tokenAddress)
  }

  // Pricing

  getPrices(): Promise<PriceMap> {
    return getPrices(this.apiClient)
  }

  private resolveVaultNetwork(vaultAddress: Address): Network {
    const config = getVaultByAddress(vaultAddress)
    if (!config) return this.network
    return config.network
  }
}
