import type { Address, PublicClient } from 'viem'
import { erc20Abi } from '../constants/abis'
import type { TokenAllowance } from '../types'
import { isNativeToken } from '../utils/native'

const MAX_UINT256 = 2n ** 256n - 1n

export async function getTokenAllowance(
  publicClient: PublicClient,
  token: Address,
  owner: Address,
  spender: Address,
): Promise<TokenAllowance> {
  if (isNativeToken(token)) {
    console.log('[getTokenAllowance] native token detected — returning MAX_UINT256')
    return { token, owner, spender, allowance: MAX_UINT256 }
  }

  const allowance = await publicClient.readContract({
    address: token,
    abi: erc20Abi,
    functionName: 'allowance',
    args: [owner, spender],
  })

  return {
    token,
    owner,
    spender,
    allowance,
  }
}

export async function hasEnoughAllowance(
  publicClient: PublicClient,
  token: Address,
  owner: Address,
  spender: Address,
  amount: bigint,
): Promise<boolean> {
  const { allowance } = await getTokenAllowance(publicClient, token, owner, spender)
  return allowance >= amount
}
