import type { Address, PublicClient } from 'viem'
import {
  quoteConvertToAssets,
  quoteConvertToShares,
  quotePreviewDeposit,
  quotePreviewRedeem,
  quotePreviewWithdraw,
  getShareAllowance,
  getAssetAllowance,
} from '../reads/gateway'
import {
  convertToAssets,
  convertToShares,
  getIdleBalance,
  getVaultState,
  isPaused,
  previewDeposit,
  previewRedeem,
} from '../reads/vault'
import type { VaultState } from '../types'

export class VaultReadService {
  constructor(private readonly publicClient: PublicClient) {}

  getVaultState(vaultAddress: Address): Promise<VaultState> {
    return getVaultState(this.publicClient, vaultAddress)
  }

  previewDeposit(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return previewDeposit(this.publicClient, vaultAddress, assets)
  }

  previewRedeem(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return previewRedeem(this.publicClient, vaultAddress, shares)
  }

  convertToAssets(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return convertToAssets(this.publicClient, vaultAddress, shares)
  }

  convertToShares(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return convertToShares(this.publicClient, vaultAddress, assets)
  }

  isPaused(vaultAddress: Address): Promise<boolean> {
    return isPaused(this.publicClient, vaultAddress)
  }

  getIdleBalance(vaultAddress: Address): Promise<bigint> {
    return getIdleBalance(this.publicClient, vaultAddress)
  }

  quotePreviewDeposit(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return quotePreviewDeposit(this.publicClient, vaultAddress, assets)
  }

  quotePreviewRedeem(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return quotePreviewRedeem(this.publicClient, vaultAddress, shares)
  }

  quotePreviewWithdraw(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return quotePreviewWithdraw(this.publicClient, vaultAddress, assets)
  }

  quoteConvertToAssets(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return quoteConvertToAssets(this.publicClient, vaultAddress, shares)
  }

  quoteConvertToShares(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return quoteConvertToShares(this.publicClient, vaultAddress, assets)
  }

  getShareAllowance(vaultAddress: Address, owner: Address): Promise<bigint> {
    return getShareAllowance(this.publicClient, vaultAddress, owner)
  }

  getAssetAllowance(vaultAddress: Address, owner: Address): Promise<bigint> {
    return getAssetAllowance(this.publicClient, vaultAddress, owner)
  }
}
