import { type Address, isAddress } from 'viem'

export function validateAddress(address: string, label: string): asserts address is Address {
  if (!isAddress(address)) {
    throw new Error(`[yo-kit] Invalid ${label} address: ${address}`)
  }
}

export function validateAmount(amount: bigint, label: string): void {
  if (amount <= 0n) {
    throw new Error(`[yo-kit] ${label} must be greater than 0`)
  }
}
