import type { Address } from 'viem'
import { type ApiClient, ApiError } from './client'
import type {
  ApiResponse,
  Network,
  PendingRedeem,
  UserBalances,
  UserHistoryItem,
  UserPerformance,
  UserPoints,
  UserSnapshot,
} from './types'

export async function getUserTransactionHistory(
  client: ApiClient,
  network: Network,
  vaultAddress: Address,
  userAddress: Address,
  limit?: number,
): Promise<UserHistoryItem[]> {
  const endpoint = client.buildUrl(
    `/api/v1/history/user/${network}/${vaultAddress}/${userAddress}`,
    { limit },
  )
  const response = await client.fetch<ApiResponse<UserHistoryItem[]>>(endpoint)
  return response.data
}

