/** @deprecated Use `getUserPerformance` instead. */
export async function getUserPoints(
  client: ApiClient,
  userAddress: Address,
): Promise<UserPoints | null> {
  try {
    const response = await client.fetch<ApiResponse<UserPoints>>(
      `/api/v1/users/wallet/${userAddress}/points`,
    )
    return response.data
  } catch (error) {
    if (error instanceof ApiError && error.statusCode === 404) {
      return null
    }
    throw error
  }
}
