import type { Address, PublicClient } from 'viem'
import {
  type PrepareApproveParams,
  type PrepareDepositWithApprovalParams,
  type PrepareRedeemWithApprovalParams,
  prepareApprove,
  prepareDeposit,
  prepareDepositWithApproval,
  prepareRedeem,
  prepareRedeemWithApproval,
} from '../actions/prepare'
import type { DepositViaGatewayParams } from '../actions/deposit'
import { type RedeemViaGatewayParams, waitForRedeemReceipt } from '../actions/redeem'
import type { SupportedChainId } from '../constants/chains'
import type {
  PreparedTransaction,
  RedeemReceipt,
  TransactionReceipt,
} from '../types'

export class TransactionService {
  constructor(
    private readonly publicClients: Record<SupportedChainId, PublicClient>,
    private readonly defaultChainId: SupportedChainId,
    private readonly partnerId: number,
  ) {}

  private getClient(chainId?: number): PublicClient {
    return this.publicClients[chainId as SupportedChainId] ?? this.publicClients[this.defaultChainId]
  }

  // Prepared transactions

  prepareApprove(params: PrepareApproveParams): PreparedTransaction {
    return prepareApprove(params)
  }

  async prepareDeposit(
    params: Omit<DepositViaGatewayParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction> {
    return prepareDeposit(this.getClient(params.chainId), {
      ...params,
      partnerId: params.partnerId ?? this.partnerId,
    })
  }

  async prepareRedeem(
    params: Omit<RedeemViaGatewayParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction> {
    return prepareRedeem(this.getClient(params.chainId), {
      ...params,
      partnerId: params.partnerId ?? this.partnerId,
    })
  }

  async prepareDepositWithApproval(
    params: Omit<PrepareDepositWithApprovalParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction[]> {
    return prepareDepositWithApproval(this.getClient(params.chainId), {
      ...params,
      partnerId: params.partnerId ?? this.partnerId,
    })
  }

  async prepareRedeemWithApproval(
    params: Omit<PrepareRedeemWithApprovalParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction[]> {
    return prepareRedeemWithApproval(this.getClient(params.chainId), {
      ...params,
      partnerId: params.partnerId ?? this.partnerId,
    })
  }

  // Confirmation

  async waitForTransaction(hash: `0x${string}`, chainId?: number): Promise<TransactionReceipt> {
    const receipt = await this.getClient(chainId).waitForTransactionReceipt({ hash })
    return {
      hash,
      status: receipt.status,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed,
    }
  }

  async waitForRedeemReceipt(hash: `0x${string}`, chainId?: number): Promise<RedeemReceipt> {
    return waitForRedeemReceipt(this.getClient(chainId), hash)
  }
}
