import type { Address, PublicClient } from 'viem'
import { erc20Abi, erc4626Abi } from '../constants/abis'
import type { SecondaryVaultInfo } from '../api/types'
import type { TokenBalance, UserVaultPosition } from '../types'

/** Minimal vault shape needed for multi-chain position fetching. Works with VaultSnapshot, VaultStatsItem, etc. */
export interface VaultLike {
  chain: { id: number }
  contracts: { vaultAddress: string }
  secondaryVaults?: SecondaryVaultInfo[]
}

export async function getTokenBalance(
  publicClient: PublicClient,
  token: Address,
  account: Address,
): Promise<TokenBalance> {
  const [balance, decimals] = await Promise.all([
    publicClient.readContract({
      address: token,
      abi: erc20Abi,
      functionName: 'balanceOf',
      args: [account],
    }),
    publicClient.readContract({
      address: token,
      abi: erc20Abi,
      functionName: 'decimals',
    }),
  ])

  return {
    token,
    balance,
    decimals,
  }
}

export async function getShareBalance(
  publicClient: PublicClient,
  vaultAddress: Address,
  account: Address,
): Promise<bigint> {
  return publicClient.readContract({
    address: vaultAddress,
    abi: erc4626Abi,
    functionName: 'balanceOf',
    args: [account],
  })
}

export async function getUserVaultPosition(
  publicClient: PublicClient,
  vaultAddress: Address,
  account: Address,
): Promise<UserVaultPosition> {
  const shares = await publicClient.readContract({
    address: vaultAddress,
    abi: erc4626Abi,
    functionName: 'balanceOf',
    args: [account],
  })

  let assets = 0n
  if (shares > 0n) {
    assets = await publicClient.readContract({
      address: vaultAddress,
      abi: erc4626Abi,
      functionName: 'previewRedeem',
      args: [shares],
    })
  }

  return {
    shares,
    assets,
  }
}

/**
 * Fetch user positions across all chains using multicall for efficiency.
 * Batches all on-chain reads per chain into minimal RPC round-trips.
 *
 * Accepts vault data from the API (VaultSnapshot[], VaultStatsItem[], or any object
 * matching VaultLike). The secondary vaults are read directly from each vault's
 * `secondaryVaults` property — no separate map needed.
 *
 * @param publicClients - A PublicClient per chain ID (1, 8453, 42161, etc.)
 * @param account - The user's address
 * @param vaults - Vault data from the API (e.g. from getVaults())
 */
export async function getUserPositionsAllChains<T extends VaultLike>(
  publicClients: Record<number, PublicClient>,
  account: Address,
  vaults: T[],
): Promise<Array<{ vault: T; position: UserVaultPosition }>> {
  if (!vaults.length) return []

  // ── Phase 1: Batch all balanceOf calls (primary + secondary) per chain ──

  type BalanceCall = { vaultIndex: number; contract: { address: Address; abi: typeof erc4626Abi | typeof erc20Abi; functionName: 'balanceOf'; args: [Address] } }
  const primaryCallsByChain = new Map<number, BalanceCall[]>()
  const secondaryCallsByChain = new Map<number, BalanceCall[]>()

  for (let i = 0; i < vaults.length; i++) {
    const v = vaults[i]!
    const chainId = v.chain.id

    // Primary vault balanceOf
    if (!primaryCallsByChain.has(chainId)) primaryCallsByChain.set(chainId, [])
    primaryCallsByChain.get(chainId)!.push({
      vaultIndex: i,
      contract: {
        address: v.contracts.vaultAddress as Address,
        abi: erc4626Abi,
        functionName: 'balanceOf' as const,
        args: [account],
      },
    })

    // Secondary vault share token balanceOf calls
    const secondaries = v.secondaryVaults
    if (secondaries?.length) {
      for (const sv of secondaries) {
        if (!publicClients[sv.chain.id]) continue
        if (!secondaryCallsByChain.has(sv.chain.id)) secondaryCallsByChain.set(sv.chain.id, [])
        secondaryCallsByChain.get(sv.chain.id)!.push({
          vaultIndex: i,
          contract: {
            address: sv.shareAsset.address as Address,
            abi: erc20Abi,
            functionName: 'balanceOf' as const,
            args: [account],
          },
        })
      }
    }
  }

  // Execute all multicalls in parallel (one per chain)
  const primaryShares = new Array<bigint>(vaults.length).fill(0n)
  const secondaryShares = new Array<bigint>(vaults.length).fill(0n)
  const multicallPromises: Promise<void>[] = []

  for (const [chainId, calls] of primaryCallsByChain) {
    const client = publicClients[chainId]
    if (!client) continue
    multicallPromises.push(
      client
        .multicall({ contracts: calls.map((c) => c.contract) })
        .then((results) => {
          for (let j = 0; j < results.length; j++) {
            const r = results[j]!
            if (r.status === 'success') {
              primaryShares[calls[j]!.vaultIndex] = r.result as bigint
            }
          }
        })
        .catch(() => {}),
    )
  }

  for (const [chainId, calls] of secondaryCallsByChain) {
    const client = publicClients[chainId]
    if (!client) continue
    multicallPromises.push(
      client
        .multicall({ contracts: calls.map((c) => c.contract) })
        .then((results) => {
          for (let j = 0; j < results.length; j++) {
            const r = results[j]!
            const idx = calls[j]!.vaultIndex
            if (r.status === 'success') {
              secondaryShares[idx] = (secondaryShares[idx] ?? 0n) + (r.result as bigint)
            }
          }
        })
        .catch(() => {}),
    )
  }

  await Promise.all(multicallPromises)

  // ── Phase 2: Batch previewRedeem calls for vaults with shares > 0 ──

  type ConvertCall = { vaultIndex: number; contract: { address: Address; abi: typeof erc4626Abi; functionName: 'previewRedeem'; args: [bigint] } }
  const convertCallsByChain = new Map<number, ConvertCall[]>()

  for (let i = 0; i < vaults.length; i++) {
    const totalShares = primaryShares[i]! + secondaryShares[i]!
    if (totalShares === 0n) continue

    const v = vaults[i]!
    const chainId = v.chain.id
    if (!convertCallsByChain.has(chainId)) convertCallsByChain.set(chainId, [])

    if (primaryShares[i]! > 0n) {
      convertCallsByChain.get(chainId)!.push({
        vaultIndex: i,
        contract: {
          address: v.contracts.vaultAddress as Address,
          abi: erc4626Abi,
          functionName: 'previewRedeem' as const,
          args: [primaryShares[i]!],
        },
      })
    }
    if (secondaryShares[i]! > 0n) {
      convertCallsByChain.get(chainId)!.push({
        vaultIndex: i,
        contract: {
          address: v.contracts.vaultAddress as Address,
          abi: erc4626Abi,
          functionName: 'previewRedeem' as const,
          args: [secondaryShares[i]!],
        },
      })
    }
  }

  const assets = new Array<bigint>(vaults.length).fill(0n)
  const convertPromises: Promise<void>[] = []

  for (const [chainId, calls] of convertCallsByChain) {
    const client = publicClients[chainId]
    if (!client) continue
    convertPromises.push(
      client
        .multicall({ contracts: calls.map((c) => c.contract) })
        .then((results) => {
          for (let j = 0; j < results.length; j++) {
            const r = results[j]!
            const idx = calls[j]!.vaultIndex
            if (r.status === 'success') {
              assets[idx] = (assets[idx] ?? 0n) + (r.result as bigint)
            }
          }
        })
        .catch(() => {}),
    )
  }

  await Promise.all(convertPromises)

  // ── Phase 3: Build result (only vaults with shares > 0) ──

  const positions: Array<{ vault: T; position: UserVaultPosition }> = []

  for (let i = 0; i < vaults.length; i++) {
    const totalShares = primaryShares[i]! + secondaryShares[i]!
    if (totalShares > 0n) {
      positions.push({
        vault: vaults[i]!,
        position: { shares: totalShares, assets: assets[i]! },
      })
    }
  }

  return positions
}
