import { DEFAULT_ASSET_IDS } from '../constants/pricing'
import type { ApiClient } from './client'
import type { ApiResponse, PriceMap } from './types'

export async function getPrices(client: ApiClient): Promise<PriceMap> {
  const response = await client.fetch<ApiResponse<PriceMap>>('/api/v1/pricing/usd', {
    method: 'POST',
    body: JSON.stringify({ ids: DEFAULT_ASSET_IDS }),
  })
  return response.data
}
