import type { Address } from 'viem'
import type { ApiClient } from './client'
import type {
  AllTimeRewardsResponse,
  ApiResponse,
  UserRewardsByAssetResponse,
  WeeklyRewardsResponse,
} from './types'
import { YO_TOKEN } from '../constants/merkl'

export async function getWeeklyRewards(
  client: ApiClient,
  tokenAddress: string,
): Promise<WeeklyRewardsResponse> {
  const response = await client.fetch<ApiResponse<WeeklyRewardsResponse>>(
    `/api/v1/rewards/weekly/${tokenAddress}`,
  )
  return response.data
}

export async function getAllTimeRewards(
  client: ApiClient,
  tokenAddress: string,
): Promise<AllTimeRewardsResponse> {
  const response = await client.fetch<ApiResponse<AllTimeRewardsResponse>>(
    `/api/v1/rewards/all-time/${tokenAddress}`,
  )
  return response.data
}

export async function getUserRewardsByAsset(
  client: ApiClient,
  userAddress: Address,
  tokenAddress: string = YO_TOKEN.address,
): Promise<UserRewardsByAssetResponse> {
  const response = await client.fetch<ApiResponse<UserRewardsByAssetResponse>>(
    `/api/v1/rewards/user/${userAddress}/${tokenAddress}`,
  )
  return response.data
}
