import { type Address, createPublicClient, http, type PublicClient } from 'viem'
import type { DepositViaGatewayParams } from './actions/deposit'
import type { PrepareApproveParams, PrepareDepositWithApprovalParams, PrepareRedeemWithApprovalParams } from './actions/prepare'
import type { RedeemViaGatewayParams } from './actions/redeem'
import type { ApiClient } from './api/client'
import { createApiClient } from './api/client'
import { createMerklApiClient, type MerklApiClient } from './api/merkl'
import type {
  AllTimeRewardsResponse,
  DailyAllocationSnapshot,
  FormattedValue,
  GlobalVaultHistoryResponse,
  Network,
  PendingRedeem,
  PerformanceBenchmark,
  PriceMap,
  SecondaryVaultInfo,
  SharePriceHistoryPoint,
  TimeseriesPoint,
  TotalTvlTimeseriesPoint,
  UserBalances,
  UserHistoryItem,
  UserPerformance,
  UserRewardsByAssetResponse,
  UserSnapshot,
  VaultActivityFilters,
  VaultHistoryResponse,
  VaultPercentile,
  VaultPerformance,
  VaultSnapshot,
  VaultStatsItem,
  WeeklyRewardsResponse,
} from './api/types'
import { CHAIN_ID_TO_NETWORK, SUPPORTED_CHAIN_IDS, SUPPORTED_CHAINS, type SupportedChainId } from './constants/chains'
import { getUserPositionsAllChains } from './reads/balance'
import type { MerklCampaignStatus } from './constants/merkl'
import {
  MerklService,
  TransactionService,
  UserReadService,
  VaultApiService,
  VaultReadService,
} from './services'
import type {
  MerklCampaign,
  MerklChainRewards,
  MerklPendingRewards,
  MerklTokenReward,
  PreparedTransaction,
  RedeemReceipt,
  TokenAllowance,
  TokenBalance,
  TransactionReceipt,
  UserVaultPosition,
  VaultState,
  YoClientConfig,
} from './types'

export class YoClient {
  public readonly chainId: SupportedChainId
  public readonly publicClient: PublicClient
  public readonly publicClients: Record<SupportedChainId, PublicClient>
  public readonly apiClient: ApiClient
  public readonly merklApiClient: MerklApiClient
  public readonly partnerId: number

  private readonly vaultReads: VaultReadService
  private readonly userReads: UserReadService
  private readonly transactions: TransactionService
  private readonly vaultApi: VaultApiService
  private readonly merkl: MerklService

  constructor(config: YoClientConfig) {
    this.chainId = config.chainId
    this.partnerId = config.partnerId ?? 9999

    // Build multi-chain public clients map — use provided or create defaults
    const clients = {} as Record<SupportedChainId, PublicClient>
    for (const cid of SUPPORTED_CHAIN_IDS) {
      if (config.publicClients?.[cid]) {
        clients[cid] = config.publicClients[cid]
      } else {
        clients[cid] = createPublicClient({
          chain: SUPPORTED_CHAINS[cid],
          transport: http(),
        }) as PublicClient
      }
    }
    this.publicClients = clients
    this.publicClient = clients[config.chainId]

    this.apiClient = createApiClient()
    this.merklApiClient = createMerklApiClient()

    this.vaultReads = new VaultReadService(this.publicClient)
    this.userReads = new UserReadService(this.publicClient)
    this.transactions = new TransactionService(this.publicClients, this.chainId, this.partnerId)
    this.vaultApi = new VaultApiService(this.apiClient, this.chainId)
    this.merkl = new MerklService(this.publicClients, this.merklApiClient)
  }

  get network(): Network {
    return CHAIN_ID_TO_NETWORK[this.chainId]
  }

  getVaults(options?: { secondary?: boolean }): Promise<VaultStatsItem[]> {
    return this.vaultApi.getVaults(options)
  }

  // Vault reads

  getVaultState(vaultAddress: Address): Promise<VaultState> {
    return this.vaultReads.getVaultState(vaultAddress)
  }

  previewDeposit(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return this.vaultReads.previewDeposit(vaultAddress, assets)
  }

  previewRedeem(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return this.vaultReads.previewRedeem(vaultAddress, shares)
  }

  convertToAssets(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return this.vaultReads.convertToAssets(vaultAddress, shares)
  }

  convertToShares(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return this.vaultReads.convertToShares(vaultAddress, assets)
  }

  isPaused(vaultAddress: Address): Promise<boolean> {
    return this.vaultReads.isPaused(vaultAddress)
  }

  getIdleBalance(vaultAddress: Address): Promise<bigint> {
    return this.vaultReads.getIdleBalance(vaultAddress)
  }

  // User reads

  getTokenBalance(token: Address, account: Address): Promise<TokenBalance> {
    return this.userReads.getTokenBalance(token, account)
  }

  getShareBalance(vaultAddress: Address, account: Address): Promise<bigint> {
    return this.userReads.getShareBalance(vaultAddress, account)
  }

  getUserPosition(vaultAddress: Address, account: Address): Promise<UserVaultPosition> {
    return this.userReads.getUserPosition(vaultAddress, account)
  }

  getAllowance(token: Address, owner: Address, spender: Address): Promise<TokenAllowance> {
    return this.userReads.getAllowance(token, owner, spender)
  }

  hasEnoughAllowance(
    token: Address,
    owner: Address,
    spender: Address,
    amount: bigint,
  ): Promise<boolean> {
    return this.userReads.hasEnoughAllowance(token, owner, spender, amount)
  }

  /**
   * Fetch user positions across ALL chains using multicall.
   * Aggregates primary + secondary vault share balances.
   *
   * If `vaults` is provided, uses that data directly.
   * Otherwise fetches vault stats from the API first.
   */
  async getUserPositionsAllChains<T extends { chain: { id: number }; contracts: { vaultAddress: string }; secondaryVaults?: SecondaryVaultInfo[] }>(
    account: Address,
    vaults?: T[],
  ): Promise<Array<{ vault: T; position: UserVaultPosition }>> {
    const vaultData = vaults ?? (await this.getVaults()) as unknown as T[]
    return getUserPositionsAllChains(this.publicClients, account, vaultData)
  }

  // Transaction confirmation

  waitForTransaction(hash: `0x${string}`, chainId?: number): Promise<TransactionReceipt> {
    return this.transactions.waitForTransaction(hash, chainId)
  }

  waitForRedeemReceipt(hash: `0x${string}`, chainId?: number): Promise<RedeemReceipt> {
    return this.transactions.waitForRedeemReceipt(hash, chainId)
  }

  // Prepared transactions

  prepareApprove(params: PrepareApproveParams): PreparedTransaction {
    return this.transactions.prepareApprove(params)
  }

  prepareDeposit(
    params: Omit<DepositViaGatewayParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction> {
    return this.transactions.prepareDeposit(params)
  }

  prepareRedeem(
    params: Omit<RedeemViaGatewayParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction> {
    return this.transactions.prepareRedeem(params)
  }

  prepareDepositWithApproval(
    params: Omit<PrepareDepositWithApprovalParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction[]> {
    return this.transactions.prepareDepositWithApproval(params)
  }

  prepareRedeemWithApproval(
    params: Omit<PrepareRedeemWithApprovalParams, 'vault'> & { vault: Address; chainId?: number },
  ): Promise<PreparedTransaction[]> {
    return this.transactions.prepareRedeemWithApproval(params)
  }

  // Gateway quote helpers

  quotePreviewDeposit(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return this.vaultReads.quotePreviewDeposit(vaultAddress, assets)
  }

  quotePreviewRedeem(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return this.vaultReads.quotePreviewRedeem(vaultAddress, shares)
  }

  quotePreviewWithdraw(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return this.vaultReads.quotePreviewWithdraw(vaultAddress, assets)
  }

  quoteConvertToAssets(vaultAddress: Address, shares: bigint): Promise<bigint> {
    return this.vaultReads.quoteConvertToAssets(vaultAddress, shares)
  }

  quoteConvertToShares(vaultAddress: Address, assets: bigint): Promise<bigint> {
    return this.vaultReads.quoteConvertToShares(vaultAddress, assets)
  }

  // Gateway allowance helpers

  getShareAllowance(vaultAddress: Address, owner: Address): Promise<bigint> {
    return this.vaultReads.getShareAllowance(vaultAddress, owner)
  }

  getAssetAllowance(vaultAddress: Address, owner: Address): Promise<bigint> {
    return this.vaultReads.getAssetAllowance(vaultAddress, owner)
  }

  // Rewards leaderboard

  getWeeklyRewards(tokenAddress: string): Promise<WeeklyRewardsResponse> {
    return this.vaultApi.getWeeklyRewards(tokenAddress)
  }

  getAllTimeRewards(tokenAddress: string): Promise<AllTimeRewardsResponse> {
    return this.vaultApi.getAllTimeRewards(tokenAddress)
  }

  // API methods

  getPrices(): Promise<PriceMap> {
    return this.vaultApi.getPrices()
  }

  getVaultHistory(vaultAddress: Address, limit?: number): Promise<VaultHistoryResponse> {
    return this.vaultApi.getVaultHistory(vaultAddress, limit)
  }

  getVaultHistoryAllNetworks(
    vaultAddress: Address,
    options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
  ): Promise<GlobalVaultHistoryResponse> {
    return this.vaultApi.getVaultHistoryAllNetworks(vaultAddress, options)
  }

  /**
   * Fetch deposit/withdrawal history across ALL vaults and networks in a single API call.
   */
  getGlobalVaultHistory(
    options?: { cursor?: number; limit?: number; filters?: VaultActivityFilters },
  ): Promise<GlobalVaultHistoryResponse> {
    return this.vaultApi.getGlobalVaultHistory(options)
  }

  getVaultSnapshot(vaultAddress: Address): Promise<VaultSnapshot> {
    return this.vaultApi.getVaultSnapshot(vaultAddress)
  }

  getVaultYieldHistory(vaultAddress: Address): Promise<TimeseriesPoint[]> {
    return this.vaultApi.getVaultYieldHistory(vaultAddress)
  }

  getVaultTvlHistory(vaultAddress: Address): Promise<TimeseriesPoint[]> {
    return this.vaultApi.getVaultTvlHistory(vaultAddress)
  }

  getTotalTvlTimeseries(): Promise<TotalTvlTimeseriesPoint[]> {
    return this.vaultApi.getTotalTvlTimeseries()
  }

  getVaultPercentile(vaultAddress: Address): Promise<VaultPercentile> {
    return this.vaultApi.getVaultPercentile(vaultAddress)
  }

  getSharePriceHistory(vaultAddress: Address): Promise<SharePriceHistoryPoint[]> {
    return this.vaultApi.getSharePriceHistory(vaultAddress)
  }

  getVaultAllocationsTimeSeries(vaultAddress: Address): Promise<DailyAllocationSnapshot[]> {
    return this.vaultApi.getVaultAllocationsTimeSeries(vaultAddress)
  }

  getUserHistory(vaultAddress: Address, user: Address, limit?: number): Promise<UserHistoryItem[]> {
    return this.vaultApi.getUserHistory(vaultAddress, user, limit)
  }

  getUserPerformance(vaultAddress: Address, user: Address): Promise<UserPerformance> {
    return this.vaultApi.getUserPerformance(vaultAddress, user)
  }

  getPendingRedemptions(vaultAddress: Address, user: Address): Promise<PendingRedeem> {
    return this.vaultApi.getPendingRedemptions(vaultAddress, user)
  }

  getVaultPendingRedeems(vaultAddress: Address): Promise<FormattedValue> {
    return this.vaultApi.getVaultPendingRedeems(vaultAddress)
  }

  getVaultPerformance(vaultAddress: Address): Promise<VaultPerformance> {
    return this.vaultApi.getVaultPerformance(vaultAddress)
  }

  getPerformanceBenchmark(vaultAddress: Address): Promise<PerformanceBenchmark> {
    return this.vaultApi.getPerformanceBenchmark(vaultAddress)
  }

  getUserSnapshots(vaultAddress: Address, user: Address): Promise<UserSnapshot[]> {
    return this.vaultApi.getUserSnapshots(vaultAddress, user)
  }

  getUserBalances(user: Address): Promise<UserBalances> {
    return this.vaultApi.getUserBalances(user)
  }

  getUserRewardsByAsset(user: Address, tokenAddress?: string): Promise<UserRewardsByAssetResponse> {
    return this.vaultApi.getUserRewardsByAsset(user, tokenAddress)
  }

  // Merkl reward methods

  getMerklCampaigns(options?: { status?: MerklCampaignStatus }): Promise<MerklCampaign[]> {
    return this.merkl.getCampaigns(options)
  }

  getMerklRewards(user: Address): Promise<MerklChainRewards | null> {
    return this.merkl.getRewards(user)
  }

  getMerklClaimedAmount(user: Address, token: Address): Promise<bigint> {
    return this.merkl.getClaimedAmount(user, token)
  }

  getClaimableRewards(user: Address): Promise<MerklChainRewards | null> {
    return this.merkl.getClaimableRewards(user)
  }

  prepareClaimMerklRewards(userAddress: Address, chainRewards: MerklChainRewards): PreparedTransaction {
    return this.merkl.prepareClaimRewards(userAddress, chainRewards)
  }

  getMerklClaimableAmount(reward: MerklTokenReward): bigint {
    return this.merkl.getClaimableAmount(reward)
  }

  hasMerklClaimableRewards(chainRewards: MerklChainRewards): boolean {
    return this.merkl.hasClaimableRewards(chainRewards)
  }

  getMerklTotalClaimable(chainRewards: MerklChainRewards): bigint {
    return this.merkl.getTotalClaimable(chainRewards)
  }

  /**
   * Fetch which campaigns/opportunities have pending (claimable) rewards for a user.
   * Returns sets of opportunity IDs and vault types for easy matching against campaigns.
   *
   * Usage:
   * ```ts
   * const pending = await client.getMerklPendingRewards(userAddress)
   * const hasPending = campaignHasPendingRewards(campaign, pending)
   * ```
   */
  getMerklPendingRewards(user: Address): Promise<MerklPendingRewards> {
    return this.merkl.getPendingRewards(user)
  }

  /**
   * Extract pending reward sets from already-fetched chain rewards.
   * Use this when you've already called `getClaimableRewards()`.
   */
  getMerklPendingRewardSets(chainRewards: MerklChainRewards | null): MerklPendingRewards {
    return this.merkl.getPendingRewardSets(chainRewards)
  }
}

export function createYoClient(config: YoClientConfig): YoClient {
  return new YoClient(config)
}
